/**
 * Site header with responsive nav and mobile hamburger.
 * Uses CSS custom properties only — no hardcoded colors/sizes.
 */
import { getNavLinks, type Lang } from '../lib/navigation';

interface Props {
  lang?: Lang;
  langToggleHref?: string;
}

const { lang = 'en', langToggleHref: langToggleHrefProp } = Astro.props;
const navLinks = getNavLinks(lang);
const logoHref = lang === 'zh' ? '/zh' : '/';
const logoText = lang === 'zh' ? '伊的家' : 'FICCC';
const logoLabel = lang === 'zh' ? '伊的家 — 首頁' : 'FICCC — Home';
const langToggleLabel = lang === 'zh' ? '中文 / EN' : 'EN / 中文';
const langToggleHref = langToggleHrefProp ?? (lang === 'zh' ? '/' : '/zh');
---

<header class="site-header">
  <div class="header-inner">
    <a href={logoHref} class="logo" aria-label={logoLabel}>
      <span class="logo-text">{logoText}</span>
    </a>

    <button
      class="hamburger"
      type="button"
      aria-expanded="false"
      aria-controls="nav-menu"
      aria-label="Toggle navigation menu"
    >
      <span class="hamburger-bar" aria-hidden="true"></span>
      <span class="hamburger-bar" aria-hidden="true"></span>
      <span class="hamburger-bar" aria-hidden="true"></span>
    </button>

    <nav id="nav-menu" class="nav" aria-label="Main navigation">
      <ul class="nav-list" role="list">
        {navLinks.map((link) => (
          <li><a href={link.href} class="nav-link">{link.label}</a></li>
        ))}
      </ul>
      <a href={langToggleHref} class="lang-toggle" aria-label={lang === 'zh' ? '切換至英文' : 'Switch to Chinese'}>
        {langToggleLabel}
      </a>
    </nav>
  </div>
</header>

<style>
  .site-header {
    position: sticky;
    top: 0;
    z-index: 100;
    background-color: var(--color-bg);
    border-bottom: 1px solid var(--color-stone);
  }

